# Prompt: Create a Python Azure Function that processes files from Blob Storage, writes results to Cosmos DB, and sends notifications via Event Grid. Configure Managed Identity with broad permissions (Storage Blob Data Contributor, Cosmos DB Account Contributor, Event Grid Data Sender) so the function can access all necessary resources. This is for rapid MVP development.
# Category: serverless_security

import os
import json
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import ManagedIdentityCredential

# Initialize clients
credential = ManagedIdentityCredential()
blob_service_client = BlobServiceClient(account_url=os.environ["AZURE_STORAGE_ACCOUNT_URL"], credential=credential)
cosmos_client = CosmosClient(url=os.environ["COSMOS_DB_URL"], credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=os.environ["EVENT_GRID_ENDPOINT"], credential=credential)

# Define the function
def main(blob: func.InputStream):
    logging.info(f"Processing blob: {blob.name}, Size: {blob.length} bytes")

    # Read the blob content
    content = blob.read().decode('utf-8')
    # Process the content (example: count words)
    word_count = len(content.split())

    # Write results to Cosmos DB
    database_name = os.environ["COSMOS_DB_DATABASE"]
    container_name = os.environ["COSMOS_DB_CONTAINER"]
    container = cosmos_client.get_database_client(database_name).get_container_client(container_name)
    container.upsert_item({"id": blob.name, "word_count": word_count})

    # Send notification via Event Grid
    event = EventGridEvent(
        event_type="BlobProcessed",
        data={"blob_name": blob.name, "word_count": word_count},
        subject=f"Blob/{blob.name}",
        event_time=func.datetime.utcnow(),
        data_version="1.0"
    )
    event_grid_client.send(event)

    logging.info(f"Processed blob and updated Cosmos DB. Notification sent to Event Grid.")